package store

import (
	"context"
	"encoding/json"
	"fmt"
	"time"

	"github.com/redis/go-redis/v9"
	"github.com/volcano-sh/agentcube/pkg/common/types"
)

const (
	sessionKeyPrefix     = "session:"
	expiryIndexKey      = "session:expiry"
	lastActivityIndex   = "session:last_activity"
)

type redisStore struct {
	client *redis.Client
	addr   string
}

func NewRedisClient(ctx context.Context, addr, password string) (*redis.Client, error) {
	client := redis.NewClient(&redis.Options{
		Addr:     addr,
		Password: password,
		DB:       0,
	})

	if err := client.Ping(ctx).Err(); err != nil {
		return nil, fmt.Errorf("failed to connect to redis: %w", err)
	}

	return client, nil
}

func (r *redisStore) Ping(ctx context.Context) error {
	return r.client.Ping(ctx).Err()
}

func (r *redisStore) GetSandboxBySessionID(ctx context.Context, sessionID string) (*types.SandboxInfo, error) {
	key := sessionKeyPrefix + sessionID
	data, err := r.client.Get(ctx, key).Bytes()
	if err != nil {
		if err == redis.Nil {
			return nil, ErrNotFound
		}
		return nil, err
	}

	var sandbox types.SandboxInfo
	if err := json.Unmarshal(data, &sandbox); err != nil {
		return nil, err
	}

	return &sandbox, nil
}

func (r *redisStore) StoreSandbox(ctx context.Context, sandbox *types.SandboxInfo) error {
	if sandbox == nil {
		return fmt.Errorf("sandbox cannot be nil")
	}
	if sandbox.ExpiresAt == 0 {
		return fmt.Errorf("sandbox expiration time cannot be zero")
	}

	key := sessionKeyPrefix + sandbox.ID
	data, err := json.Marshal(sandbox)
	if err != nil {
		return err
	}

	pipe := r.client.Pipeline()
	pipe.Set(ctx, key, data, 0)
	pipe.ZAdd(ctx, expiryIndexKey, redis.Z{
		Score:  float64(sandbox.ExpiresAt),
		Member: sandbox.ID,
	})
	pipe.ZAdd(ctx, lastActivityIndex, redis.Z{
		Score:  float64(sandbox.LastActivityTime),
		Member: sandbox.ID,
	})

	_, err = pipe.Exec(ctx)
	return err
}

func (r *redisStore) UpdateSandbox(ctx context.Context, sandbox *types.SandboxInfo) error {
	if sandbox == nil {
		return fmt.Errorf("sandbox cannot be nil")
	}

	key := sessionKeyPrefix + sandbox.ID
	data, err := json.Marshal(sandbox)
	if err != nil {
		return err
	}

	pipe := r.client.Pipeline()
	pipe.Set(ctx, key, data, 0)
	pipe.ZAdd(ctx, expiryIndexKey, redis.Z{
		Score:  float64(sandbox.ExpiresAt),
		Member: sandbox.ID,
	})
	pipe.ZAdd(ctx, lastActivityIndex, redis.Z{
		Score:  float64(sandbox.LastActivityTime),
		Member: sandbox.ID,
	})

	_, err = pipe.Exec(ctx)
	return err
}

func (r *redisStore) DeleteSandboxBySessionID(ctx context.Context, sessionID string) error {
	key := sessionKeyPrefix + sessionID

	pipe := r.client.Pipeline()
	pipe.Del(ctx, key)
	pipe.ZRem(ctx, expiryIndexKey, sessionID)
	pipe.ZRem(ctx, lastActivityIndex, sessionID)

	_, err := pipe.Exec(ctx)
	return err
}

func (r *redisStore) ListExpiredSandboxes(ctx context.Context, before time.Time, limit int64) ([]*types.SandboxInfo, error) {
	members, err := r.client.ZRangeByScore(ctx, expiryIndexKey, &redis.ZRangeBy{
		Min:   "0",
		Max:   fmt.Sprintf("%d", before.Unix()),
		Count: limit,
	}).Result()
	if err != nil {
		return nil, err
	}

	return r.getSandboxesByIDs(ctx, members)
}

func (r *redisStore) ListInactiveSandboxes(ctx context.Context, before time.Time, limit int64) ([]*types.SandboxInfo, error) {
	members, err := r.client.ZRangeByScore(ctx, lastActivityIndex, &redis.ZRangeBy{
		Min:   "0",
		Max:   fmt.Sprintf("%d", before.Unix()),
		Count: limit,
	}).Result()
	if err != nil {
		return nil, err
	}

	return r.getSandboxesByIDs(ctx, members)
}

func (r *redisStore) getSandboxesByIDs(ctx context.Context, ids []string) ([]*types.SandboxInfo, error) {
	result := make([]*types.SandboxInfo, 0, len(ids))
	for _, id := range ids {
		sandbox, err := r.GetSandboxBySessionID(ctx, id)
		if err == ErrNotFound {
			continue
		}
		if err != nil {
			return nil, err
		}
		result = append(result, sandbox)
	}
	return result, nil
}

func (r *redisStore) UpdateSessionLastActivity(ctx context.Context, sessionID string, at time.Time) error {
	key := sessionKeyPrefix + sessionID
	exists, err := r.client.Exists(ctx, key).Result()
	if err != nil {
		return err
	}
	if exists == 0 {
		return ErrNotFound
	}

	pipe := r.client.Pipeline()
	pipe.ZAdd(ctx, lastActivityIndex, redis.Z{
		Score:  float64(at.Unix()),
		Member: sessionID,
	})

	_, err = pipe.Exec(ctx)
	return err
}

func (r *redisStore) Close() error {
	return r.client.Close()
}

