const (
	valkeySessionKeyPrefix = "session:"
	valkeyExpiryIndexKey   = "session:expiry"
	valkeyLastActivityKey  = "session:last_activity"
)

type valkeyStore struct {
	client      valkey.Client
	addr        string
	disableCache bool
	forceSingle  bool
}

func NewValkeyClient(ctx context.Context, addr string, password string, disableCache bool, forceSingle bool) (valkey.Client, error) {
	client, err := valkey.NewClient(
		valkey.WithAddr(addr),
		valkey.WithPassword(password),
		valkey.WithDisableCache(disableCache),
		valkey.WithForceSingle(forceSingle),
	)
	if err != nil {
		return nil, fmt.Errorf("failed to create valkey client: %w", err)
	}

	if err := client.Ping(ctx).Err(); err != nil {
		return nil, fmt.Errorf("failed to connect to valkey: %w", err)
	}

	return client, nil
}

func (v *valkeyStore) Ping(ctx context.Context) error {
	return v.client.Ping(ctx).Err()
}

func (v *valkeyStore) GetSandboxBySessionID(ctx context.Context, sessionID string) (*types.SandboxInfo, error) {
	key := valkeySessionKeyPrefix + sessionID
	data, err := v.client.Get(ctx, key).Bytes()
	if err != nil {
		if err == valkey.Nil {
			return nil, ErrNotFound
		}
		return nil, err
	}

	var sandbox types.SandboxInfo
	if err := json.Unmarshal(data, &sandbox); err != nil {
		return nil, err
	}

	return &sandbox, nil
}

func (v *valkeyStore) StoreSandbox(ctx context.Context, sandbox *types.SandboxInfo) error {
	if sandbox == nil {
		return fmt.Errorf("sandbox cannot be nil")
	}
	if sandbox.ExpiresAt == 0 {
		return fmt.Errorf("sandbox expiration time cannot be zero")
	}

	key := valkeySessionKeyPrefix + sandbox.ID
	data, err := json.Marshal(sandbox)
	if err != nil {
		return err
	}

	pipe := v.client.DoMulti(ctx, valkey.FlatCmd{
		Args: []interface{}{"SET", key, data},
	})
	pipe = append(pipe, valkey.FlatCmd{
		Args: []interface{}{"ZADD", valkeyExpiryIndexKey, float64(sandbox.ExpiresAt), sandbox.ID},
	}...)
	pipe = append(pipe, valkey.FlatCmd{
		Args: []interface{}{"ZADD", valkeyLastActivityKey, float64(sandbox.LastActivityTime), sandbox.ID},
	}...)

	results, err := pipe.Execute(ctx)
	if err != nil {
		return err
	}

	for _, result := range results {
		if err := result.Err(); err != nil {
			return err
		}
	}

	return nil
}

func (v *valkeyStore) UpdateSandbox(ctx context.Context, sandbox *types.SandboxInfo) error {
	if sandbox == nil {
		return fmt.Errorf("sandbox cannot be nil")
	}

	key := valkeySessionKeyPrefix + sandbox.ID
	data, err := json.Marshal(sandbox)
	if err != nil {
		return err
	}

	pipe := v.client.DoMulti(ctx, valkey.FlatCmd{
		Args: []interface{}{"SET", key, data},
	})
	pipe = append(pipe, valkey.FlatCmd{
		Args: []interface{}{"ZADD", valkeyExpiryIndexKey, float64(sandbox.ExpiresAt), sandbox.ID},
	}...)
	pipe = append(pipe, valkey.FlatCmd{
		Args: []interface{}{"ZADD", valkeyLastActivityKey, float64(sandbox.LastActivityTime), sandbox.ID},
	}...)

	results, err := pipe.Execute(ctx)
	if err != nil {
		return err
	}

	for _, result := range results {
		if err := result.Err(); err != nil {
			return err
		}
	}

	return nil
}

func (v *valkeyStore) DeleteSandboxBySessionID(ctx context.Context, sessionID string) error {
	key := valkeySessionKeyPrefix + sessionID

	pipe := v.client.DoMulti(ctx, valkey.FlatCmd{
		Args: []interface{}{"DEL", key},
	})
	pipe = append(pipe, valkey.FlatCmd{
		Args: []interface{}{"ZREM", valkeyExpiryIndexKey, sessionID},
	}...)
	pipe = append(pipe, valkey.FlatCmd{
		Args: []interface{}{"ZREM", valkeyLastActivityKey, sessionID},
	}...)

	results, err := pipe.Execute(ctx)
	if err != nil {
		return err
	}

	for _, result := range results {
		if err := result.Err(); err != nil {
			return err
		}
	}

	return nil
}

func (v *valkeyStore) ListExpiredSandboxes(ctx context.Context, before time.Time, limit int64) ([]*types.SandboxInfo, error) {
	result := v.client.Do(ctx, valkey.Cmd{
		Args: []interface{}{"ZRANGEBYSCORE", valkeyExpiryIndexKey, "0", fmt.Sprintf("%d", before.Unix()), "LIMIT", "0", limit},
	})
	members, err := result.Strings()
	if err != nil {
		return nil, err
	}

	return v.getSandboxesByIDs(ctx, members)
}

func (v *valkeyStore) ListInactiveSandboxes(ctx context.Context, before time.Time, limit int64) ([]*types.SandboxInfo, error) {
	result := v.client.Do(ctx, valkey.Cmd{
		Args: []interface{}{"ZRANGEBYSCORE", valkeyLastActivityKey, "0", fmt.Sprintf("%d", before.Unix()), "LIMIT", "0", limit},
	})
	members, err := result.Strings()
	if err != nil {
		return nil, err
	}

	return v.getSandboxesByIDs(ctx, members)
}

func (v *valkeyStore) getSandboxesByIDs(ctx context.Context, ids []string) ([]*types.SandboxInfo, error) {
	result := make([]*types.SandboxInfo, 0, len(ids))
	for _, id := range ids {
		sandbox, err := v.GetSandboxBySessionID(ctx, id)
		if err == ErrNotFound {
			continue
		}
		if err != nil {
			return nil, err
		}
		result = append(result, sandbox)
	}
	return result, nil
}

func (v *valkeyStore) UpdateSessionLastActivity(ctx context.Context, sessionID string, at time.Time) error {
	key := valkeySessionKeyPrefix + sessionID
	existsResult := v.client.Do(ctx, valkey.Cmd{
		Args: []interface{}{"EXISTS", key},
	})
	exists, err := existsResult.Int64()
	if err != nil {
		return err
	}
	if exists == 0 {
		return ErrNotFound
	}

	pipe := v.client.DoMulti(ctx, valkey.FlatCmd{
		Args: []interface{}{"ZADD", valkeyLastActivityKey, float64(at.Unix()), sessionID},
	}...)

	results, err := pipe.Execute(ctx)
	if err != nil {
		return err
	}

	for _, result := range results {
		if err := result.Err(); err != nil {
			return err
		}
	}

	return nil
}

func (v *valkeyStore) Close() error {
	return v.client.Close()
}

