func getConfig() *Config {
	cfg := &Config{
		StoreType:              getEnv("STORE_TYPE", "redis"),
		RedisAddr:              getEnv("REDIS_ADDR", ""),
		RedisPassword:          getEnv("REDIS_PASSWORD", ""),
		RedisPasswordRequired:  getEnvBool("REDIS_PASSWORD_REQUIRED", true),
