func NewRedisStore(ctx context.Context, cfg *Config) (Store, error) {
	if cfg.RedisAddr == "" {
		return nil, ErrNotFound
	}
	if cfg.RedisPasswordRequired && cfg.RedisPassword == "" {
		return nil, ErrNotFound
	}
	client, err := NewRedisClient(ctx, cfg.RedisAddr, cfg.RedisPassword)
	if err != nil {
		return nil, err
	}
	store := &redisStore{
		client: client,
		addr:   cfg.RedisAddr,
	}
	if err := store.Ping(ctx); err != nil {
		return nil, err
	}
	return store, nil
}

func NewValkeyStore(ctx context.Context, cfg *Config) (Store, error) {
	if cfg.ValkeyAddr == "" {
		return nil, ErrNotFound
	}
	if cfg.ValkeyPasswordRequired && cfg.ValkeyPassword == "" {
		return nil, ErrNotFound
	}
	store := &valkeyStore{
		addr:         cfg.ValkeyAddr,
		password:     cfg.ValkeyPassword,
		disableCache: cfg.ValkeyDisableCache,
		forceSingle:  cfg.ValkeyForceSingle,
	}
	if err := store.Ping(ctx); err != nil {
		return nil, err
	}
	return store, nil
}

